const now = new Date();

// Bu hafta: dün - 7 gün önce
const end = new Date(now);
end.setDate(end.getDate() - 1);

const start = new Date(end);
start.setDate(start.getDate() - 6);

// Önceki hafta: 8 gün önce - 15 gün önce
const prevEnd = new Date(now);
prevEnd.setDate(prevEnd.getDate() - 8);

const prevStart = new Date(prevEnd);
prevStart.setDate(prevStart.getDate() - 6);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    thisWeekStart: fmt(start),
    thisWeekEnd: fmt(end),
    prevWeekStart: fmt(prevStart),
    prevWeekEnd: fmt(prevEnd),
    reportLabel: `${fmt(start)} → ${fmt(end)}`
  }
}];

// Bu haftanın verileri
const thisWeekRows = $('GSC Bu Hafta').first().json.rows || [];
// Önceki haftanın verileri
const prevWeekRows = $('GSC Önceki Hafta').first().json.rows || [];
const reportLabel = $('Tarih Hesapla').first().json.reportLabel;

// Sayfa bazlı harita (slug → position)
const prevMap = {};
for (const row of prevWeekRows) {
  const page = row.keys[0];
  prevMap[page] = row;
}

// Analiz
const drops = [];
const lines = [];
let totalClicks = 0;
let totalImpressions = 0;

for (const row of thisWeekRows) {
  const page = row.keys[0];
  const slug = page.replace('https://www.verimio.com.tr/blog/', '').replace('https://www.verimio.com.tr/', '');
  const clicks = row.clicks || 0;
  const impressions = row.impressions || 0;
  const pos = row.position ? row.position.toFixed(1) : '?';
  const ctr = row.ctr ? (row.ctr * 100).toFixed(1) + '%' : '?';

  totalClicks += clicks;
  totalImpressions += impressions;

  // Pozisyon karşılaştırması
  let posChange = '';
  if (prevMap[page] && prevMap[page].position) {
    const diff = row.position - prevMap[page].position;
    if (diff > 5) {
      drops.push({ slug, diff: diff.toFixed(1), pos });
      posChange = ` ↓${diff.toFixed(1)}`;
    } else if (diff < -2) {
      posChange = ` ↑${Math.abs(diff).toFixed(1)}`;
    }
  }

  lines.push(`📄 /${slug}\n   👆 ${clicks} tık | 👁 ${impressions} gösterim | #${pos}${posChange} | %${ctr}`);
}

// Mesaj formatla
const emoji = drops.length > 0 ? '⚠️' : '✅';
let message = `${emoji} Verimio Haftalık SEO Raporu\n${reportLabel}\n\n`;
message += `📊 ÖZET\n`;
message += `• Toplam tıklanma: ${totalClicks}\n`;
message += `• Toplam gösterim: ${totalImpressions}\n`;
message += `• Ortalama CTR: ${totalClicks && totalImpressions ? ((totalClicks/totalImpressions)*100).toFixed(1) : 0}%\n\n`;
message += `📝 SAYFA BAZLI\n`;
message += lines.join('\n\n') || 'Veri yok';

if (drops.length > 0) {
  message += '\n\n🚨 POZİSYON DÜŞÜŞLERİ (5+ basamak)\n';
  for (const d of drops) {
    message += `• /${d.slug}: #${d.pos} (↓${d.diff} basamak)\n`;
  }
}

return [{
  json: {
    message,
    drops,
    hasDrops: drops.length > 0,
    totalClicks,
    totalImpressions,
    reportLabel,
    topPages: thisWeekRows.slice(0, 5).map(r => r.keys[0])
  }
}];

// Her düşen sayfa için ayrı Notion görevi oluştur
const drops = $input.first().json.drops;
const results = [];

for (const drop of drops) {
  const payload = JSON.stringify({
    parent: {database_id: '31304c58-4ec9-81a1-b847-c1a28cd431e1'},
    properties: {
      'Görev': {title: [{text: {content: `SEO İnceleme: ${drop.slug} (↓${drop.diff} basamak)`}}]},
      'Durum': {select: {name: 'Backlog'}},
      'Alan': {select: {name: '🌐 Ürün & Site'}},
      'Proje': {select: {name: 'SEO Altyapısı'}},
      'Öncelik': {select: {name: 'Yüksek'}}
    }
  });
  results.push({json: {payload, slug: drop.slug}});
}

return results;
